INSERT INTO pgzc_algorithm (id, algorithm_name, algorithm_type, equipment_type, algorithm_desc, algorithm_version, algorithm_code_url, base_flag, publish_status, status, del_flag, create_by, create_time, update_by, update_time, remark) VALUES (136, '熵值法', '权重分配', '', '针对每个指标，通过分析其在不同方案中的取值占比，计算相对熵值，相对熵值反映了指标对于方案多样性的贡献程度，越大表示指标对决策的影响越大，根据相对熵值，计算每个指标的权重。相对熵值越大，最终的权重也越大', 'V1', 'algs/weight/cal_weight.zip', 0, 'DRAFT', 'ENABLED', '0', 'admin', CAST('2023-05-31 17:58:18' AS TIMESTAMP), 'admin', NULL, NULL);
INSERT INTO pgzc_algorithm (id, algorithm_name, algorithm_type, equipment_type, algorithm_desc, algorithm_version, algorithm_code_url, base_flag, publish_status, status, del_flag, create_by, create_time, update_by, update_time, remark) VALUES (164, '计算均值', '指标量化算法', '', NULL, 'V1', 'algs/norm/calMean.zip', 0, 'DRAFT', 'ENABLED', '0', 'admin', CAST('2023-12-28 15:41:25' AS TIMESTAMP), 'admin', CAST('2023-12-28 15:41:25' AS TIMESTAMP), NULL);
INSERT INTO pgzc_algorithm (id, algorithm_name, algorithm_type, equipment_type, algorithm_desc, algorithm_version, algorithm_code_url, base_flag, publish_status, status, del_flag, create_by, create_time, update_by, update_time, remark) VALUES (167, '系统不可用率', '指标量化算法', '', NULL, 'V1', 'algs/norm/systemLoss.zip', 0, 'DRAFT', 'ENABLED', '0', 'admin', CAST('2023-07-02 18:02:11' AS TIMESTAMP), NULL, NULL, NULL);
INSERT INTO pgzc_algorithm (id, algorithm_name, algorithm_type, equipment_type, algorithm_desc, algorithm_version, algorithm_code_url, base_flag, publish_status, status, del_flag, create_by, create_time, update_by, update_time, remark) VALUES (168, 'asdas', '其它算法', '', NULL, 'V1', NULL, 0, 'DRAFT', 'ENABLED', '0', 'admin', CAST('2023-07-25 10:34:55' AS TIMESTAMP), NULL, NULL, NULL);
INSERT INTO pgzc_algorithm (id, algorithm_name, algorithm_type, equipment_type, algorithm_desc, algorithm_version, algorithm_code_url, base_flag, publish_status, status, del_flag, create_by, create_time, update_by, update_time, remark) VALUES (169, '曲线趋势检测算法', '其它算法', '', '曲线趋势检测算法', 'V1', 'algs/others/coxxx.zip', 0, 'DRAFT', 'ENABLED', '0', 'admin', NULL, NULL, NULL, NULL);
INSERT INTO pgzc_algorithm (id, algorithm_name, algorithm_type, equipment_type, algorithm_desc, algorithm_version, algorithm_code_url, base_flag, publish_status, status, del_flag, create_by, create_time, update_by, update_time, remark) VALUES (170, '报告所需对齐算法（系统所需）', '其它算法', '', '报告所需对齐算法（系统所需）', 'V1', 'algs/others/combine.zip', 0, 'DRAFT', 'ENABLED', '0', 'admin', NULL, NULL, NULL, NULL);
INSERT INTO pgzc_algorithm (id, algorithm_name, algorithm_type, equipment_type, algorithm_desc, algorithm_version, algorithm_code_url, base_flag, publish_status, status, del_flag, create_by, create_time, update_by, update_time, remark) VALUES (171, '排序算法', '指标量化算法', '', '基于遥测数据的所有属性值进行升序排序，返回排序后的索引，创建一个和sorted_index相同shape的空数组，按照排序后的索引赋值排名，将排名进行归一化处理。', 'V1', 'algs/norm/rank_method.zip', 0, 'DRAFT', 'ENABLED', '0', 'admin', CAST('2023-08-08 10:08:48' AS TIMESTAMP), 'admin', NULL, NULL);
INSERT INTO pgzc_algorithm (id, algorithm_name, algorithm_type, equipment_type, algorithm_desc, algorithm_version, algorithm_code_url, base_flag, publish_status, status, del_flag, create_by, create_time, update_by, update_time, remark) VALUES (172, '逼近理想解（topsis）', '方案评价', '', '算法将决策问题转化为一个决策矩阵，其中每一行代表一个候选方案；对于每个指标，确定最大值和最小值，构建理想解和负理想解；计算每个方案到理想解和负理想解的欧几里得距离或其他距离度量；根据方案到理想解的距离和方案到负理想解的距离，计算综合得分。得分越高表示方案越优越。根据综合得分对方案进行排序，得分越高的排在前面，从而确定最优解。', 'V1', 'algs/assess/topsis.zip', 0, 'DRAFT', 'ENABLED', '0', 'admin', CAST('2023-08-10 15:10:30' AS TIMESTAMP), 'admin', NULL, NULL);
INSERT INTO pgzc_algorithm (id, algorithm_name, algorithm_type, equipment_type, algorithm_desc, algorithm_version, algorithm_code_url, base_flag, publish_status, status, del_flag, create_by, create_time, update_by, update_time, remark) VALUES (173, '推力器算法（旧版）', '指标量化算法', '', '推力器算法（旧版）', 'V1', 'algs/norm/thruster_rel.zip', 1, 'DRAFT', 'ENABLED', '0', 'admin', NULL, NULL, NULL, NULL);
INSERT INTO pgzc_algorithm (id, algorithm_name, algorithm_type, equipment_type, algorithm_desc, algorithm_version, algorithm_code_url, base_flag, publish_status, status, del_flag, create_by, create_time, update_by, update_time, remark) VALUES (174, '中心化', '指标量化算法', '', NULL, 'V1', 'algs/norm/centralize.zip', 0, 'DRAFT', 'ENABLED', '0', 'admin', CAST('2023-08-10 17:06:23' AS TIMESTAMP), NULL, NULL, NULL);
INSERT INTO pgzc_algorithm (id, algorithm_name, algorithm_type, equipment_type, algorithm_desc, algorithm_version, algorithm_code_url, base_flag, publish_status, status, del_flag, create_by, create_time, update_by, update_time, remark) VALUES (176, '均值化算法', '指标量化算法', '', '基于遥测数据的所有属性值取均值，作为每一个指标的基准值。将每一个属性值除以该基准值的商作为量化的基础，将每一个遥测数据的商进行归一化处理。', 'V1', 'algs/norm/mean_normalize.zip', 0, 'DRAFT', 'ENABLED', '0', 'admin', CAST('2023-08-12 20:10:03' AS TIMESTAMP), 'admin', NULL, NULL);
INSERT INTO pgzc_algorithm (id, algorithm_name, algorithm_type, equipment_type, algorithm_desc, algorithm_version, algorithm_code_url, base_flag, publish_status, status, del_flag, create_by, create_time, update_by, update_time, remark) VALUES (177, '中心化算法', '指标量化算法', '', NULL, 'V1', 'algs/norm/centralize.zip', 0, 'DRAFT', 'ENABLED', '0', 'admin', CAST('2023-08-12 20:26:43' AS TIMESTAMP), NULL, NULL, NULL);
INSERT INTO pgzc_algorithm (id, algorithm_name, algorithm_type, equipment_type, algorithm_desc, algorithm_version, algorithm_code_url, base_flag, publish_status, status, del_flag, create_by, create_time, update_by, update_time, remark) VALUES (178, '标准差高斯', '指标量化算法', '', NULL, 'V1', 'algs/norm/gaussian_func_std.zip', 1, 'DRAFT', 'ENABLED', '0', 'admin', CAST('2023-08-13 11:40:55' AS TIMESTAMP), NULL, NULL, NULL);
INSERT INTO pgzc_algorithm (id, algorithm_name, algorithm_type, equipment_type, algorithm_desc, algorithm_version, algorithm_code_url, base_flag, publish_status, status, del_flag, create_by, create_time, update_by, update_time, remark) VALUES (180, '归一化算法', '指标量化算法', '', NULL, 'V1', 'algs/norm/range_method.zip', 0, 'DRAFT', 'ENABLED', '0', 'admin', CAST('2023-08-13 17:15:51' AS TIMESTAMP), NULL, NULL, NULL);
INSERT INTO pgzc_algorithm (id, algorithm_name, algorithm_type, equipment_type, algorithm_desc, algorithm_version, algorithm_code_url, base_flag, publish_status, status, del_flag, create_by, create_time, update_by, update_time, remark) VALUES (181, '极差法', '指标量化算法', '', '基于遥测值计算正向分布时该遥测所处的位置，即将该遥测与最小值的距离与最大值与最小值的距离做比，该比率作为极差法的评估结果。', 'V1', 'algs/norm/normalized_range_method.zip', 0, 'DRAFT', 'ENABLED', '0', 'admin', CAST('2023-08-13 17:26:28' AS TIMESTAMP), 'admin', NULL, NULL);
INSERT INTO pgzc_algorithm (id, algorithm_name, algorithm_type, equipment_type, algorithm_desc, algorithm_version, algorithm_code_url, base_flag, publish_status, status, del_flag, create_by, create_time, update_by, update_time, remark) VALUES (184, ' 正向化算法', '指标量化算法', '', NULL, 'V1', 'algs/norm/forward_normalize.zip', 0, 'DRAFT', 'ENABLED', '0', 'admin', CAST('2023-08-14 10:52:58' AS TIMESTAMP), NULL, NULL, NULL);
INSERT INTO pgzc_algorithm (id, algorithm_name, algorithm_type, equipment_type, algorithm_desc, algorithm_version, algorithm_code_url, base_flag, publish_status, status, del_flag, create_by, create_time, update_by, update_time, remark) VALUES (185, '逆向化算法', '指标量化算法', '', NULL, 'V1', 'algs/norm/inverse_normalize.zip', 0, 'DRAFT', 'ENABLED', '0', 'admin', CAST('2023-08-14 10:53:50' AS TIMESTAMP), NULL, NULL, NULL);
INSERT INTO pgzc_algorithm (id, algorithm_name, algorithm_type, equipment_type, algorithm_desc, algorithm_version, algorithm_code_url, base_flag, publish_status, status, del_flag, create_by, create_time, update_by, update_time, remark) VALUES (186, 'z-score算法', '指标量化算法', '', '计算遥测数据点与平均值之间的差，然后除以标准差，得到一个相对于平均值的标准化偏离程度。用于比较不同数据点相对于其所属数据集的位置，以及它们相对于平均值的偏离程度。
INSERT INTO pgzc_algorithm (id, algorithm_name, algorithm_type, equipment_type, algorithm_desc, algorithm_version, algorithm_code_url, base_flag, publish_status, status, del_flag, create_by, create_time, update_by, update_time, remark) VALUES (187, '区间化算法旧', '指标量化算法', '', NULL, 'V1', 'algs/norm/intervalize.zip', 0, 'DRAFT', 'ENABLED', '0', 'admin', CAST('2023-08-14 11:18:24' AS TIMESTAMP), NULL, NULL, NULL);
INSERT INTO pgzc_algorithm (id, algorithm_name, algorithm_type, equipment_type, algorithm_desc, algorithm_version, algorithm_code_url, base_flag, publish_status, status, del_flag, create_by, create_time, update_by, update_time, remark) VALUES (188, '向量归一化算法', '指标量化算法', '', '基于遥测数据的属性值向量的模的平方，再将该向量模的平方最为归一化的基准计算评估值。', 'V1', 'algs/norm/ssn_normalize.zip', 0, 'DRAFT', 'ENABLED', '0', 'admin', CAST('2023-08-14 11:19:40' AS TIMESTAMP), 'admin', NULL, NULL);
INSERT INTO pgzc_algorithm (id, algorithm_name, algorithm_type, equipment_type, algorithm_desc, algorithm_version, algorithm_code_url, base_flag, publish_status, status, del_flag, create_by, create_time, update_by, update_time, remark) VALUES (189, '最大值法', '指标量化算法', '', NULL, 'V1', 'algs/norm/max_normalize.zip', 0, 'DRAFT', 'ENABLED', '0', 'admin', CAST('2023-08-14 11:20:40' AS TIMESTAMP), NULL, NULL, NULL);
INSERT INTO pgzc_algorithm (id, algorithm_name, algorithm_type, equipment_type, algorithm_desc, algorithm_version, algorithm_code_url, base_flag, publish_status, status, del_flag, create_by, create_time, update_by, update_time, remark) VALUES (190, '标准化算法', '指标量化算法', '', NULL, 'V1', 'algs/norm/standardize.zip', 0, 'DRAFT', 'ENABLED', '0', 'admin', CAST('2023-08-14 11:21:31' AS TIMESTAMP), NULL, NULL, NULL);
INSERT INTO pgzc_algorithm (id, algorithm_name, algorithm_type, equipment_type, algorithm_desc, algorithm_version, algorithm_code_url, base_flag, publish_status, status, del_flag, create_by, create_time, update_by, update_time, remark) VALUES (191, '求和归一化算法', '指标量化算法', '', NULL, 'V1', 'algs/norm/sum_normalize.zip', 0, 'DRAFT', 'ENABLED', '0', 'admin', CAST('2023-08-14 11:22:13' AS TIMESTAMP), NULL, NULL, NULL);
INSERT INTO pgzc_algorithm (id, algorithm_name, algorithm_type, equipment_type, algorithm_desc, algorithm_version, algorithm_code_url, base_flag, publish_status, status, del_flag, create_by, create_time, update_by, update_time, remark) VALUES (192, '加权和算法', '权重传导', '', '通过每一个指标的权重和其对应的评估值计算其加权后的评估值，并将所有加权后的评估值进行求和。', 'V1', 'algs/conduction/weighted_sum_method.zip', 0, 'DRAFT', 'ENABLED', '0', 'admin', CAST('2023-08-14 11:23:35' AS TIMESTAMP), 'admin', NULL, NULL);
INSERT INTO pgzc_algorithm (id, algorithm_name, algorithm_type, equipment_type, algorithm_desc, algorithm_version, algorithm_code_url, base_flag, publish_status, status, del_flag, create_by, create_time, update_by, update_time, remark) VALUES (193, '加权积算法', '权重传导', '', '针对每一个评估值使其与对应的权重做幂运算，再将所有的结果相乘，计算加权指标组合的总体表现。', 'V1', 'algs/conduction/weighted_product_method.zip', 0, 'DRAFT', 'ENABLED', '0', 'admin', CAST('2023-08-14 11:24:04' AS TIMESTAMP), 'admin', NULL, NULL);
INSERT INTO pgzc_algorithm (id, algorithm_name, algorithm_type, equipment_type, algorithm_desc, algorithm_version, algorithm_code_url, base_flag, publish_status, status, del_flag, create_by, create_time, update_by, update_time, remark) VALUES (195, '漂移度检测算法', '其它算法', '', '算法将所有的方案排序结果生成结果矩阵，通过将结果矩阵中的所有列表的数据进行当前数据分布与基准模型之间的漂移度检测，表示数据分布的变化程度。漂移度超过0.35时，即漂移检测结果认为该方案评价结果偏差过大，评价结果可信度较低。', 'V1', 'algs/others/result_analyze.zip', 0, 'DRAFT', 'ENABLED', '0', 'admin', NULL, 'admin', NULL, NULL);
INSERT INTO pgzc_algorithm (id, algorithm_name, algorithm_type, equipment_type, algorithm_desc, algorithm_version, algorithm_code_url, base_flag, publish_status, status, del_flag, create_by, create_time, update_by, update_time, remark) VALUES (197, '一致性算法', '其它算法', '', '算法将所有的通过漂移度检测的方案排序结果生成结果矩阵，通过肯德尔和谐系数公式得到所有评估次序的一致性，如果计算的数据较大，认为评估结果较一致。', 'V1', 'algs/others/Consistency_analysis.zip', 0, 'DRAFT', 'ENABLED', '0', 'admin', NULL, 'admin', NULL, NULL);
INSERT INTO pgzc_algorithm (id, algorithm_name, algorithm_type, equipment_type, algorithm_desc, algorithm_version, algorithm_code_url, base_flag, publish_status, status, del_flag, create_by, create_time, update_by, update_time, remark) VALUES (198, '比重法', '指标量化算法', '', '基于遥测数据的属性值取其占该条遥测数据的比重值。将该比重值进行归一化处理。', 'V1', 'algs/norm/weight_computation.zip', 0, 'DRAFT', 'ENABLED', '0', 'admin', CAST('2023-08-16 17:07:48' AS TIMESTAMP), 'admin', NULL, NULL);
INSERT INTO pgzc_algorithm (id, algorithm_name, algorithm_type, equipment_type, algorithm_desc, algorithm_version, algorithm_code_url, base_flag, publish_status, status, del_flag, create_by, create_time, update_by, update_time, remark) VALUES (200, '主成分分析算法', '权重分配', '', '根据遥测数据的残差值计算各指标的相关系数矩阵，并进行线性检查。对通过线性检查的数据获取特征值和方差解释率，获取载荷系数，计算线性组合系数和综合得分系数，并以此计算每一个遥测数据的权重值。
INSERT INTO pgzc_algorithm (id, algorithm_name, algorithm_type, equipment_type, algorithm_desc, algorithm_version, algorithm_code_url, base_flag, publish_status, status, del_flag, create_by, create_time, update_by, update_time, remark) VALUES (201, '推力器算法（新）', '指标量化算法', '', NULL, 'V1', 'algs/norm/thruster_rel_new.zip', 1, 'DRAFT', 'ENABLED', '0', 'admin', CAST('2023-08-22 16:35:56' AS TIMESTAMP), NULL, NULL, NULL);
INSERT INTO pgzc_algorithm (id, algorithm_name, algorithm_type, equipment_type, algorithm_desc, algorithm_version, algorithm_code_url, base_flag, publish_status, status, del_flag, create_by, create_time, update_by, update_time, remark) VALUES (202, '初值化算法', '指标量化算法', '', NULL, 'V1', 'algs/norm/init_normalize.zip', 0, 'DRAFT', 'ENABLED', '0', 'admin', CAST('2023-08-22 17:22:26' AS TIMESTAMP), NULL, NULL, NULL);
INSERT INTO pgzc_algorithm (id, algorithm_name, algorithm_type, equipment_type, algorithm_desc, algorithm_version, algorithm_code_url, base_flag, publish_status, status, del_flag, create_by, create_time, update_by, update_time, remark) VALUES (204, '系统效能（SEA）算法', '权重传导', '', '设置所有指标值的上下界信息，通过归一化计算得到该条指标的效能。遍历每个系统数据，不断更新系统效能值，直到得到整个系统的效能。', 'V1', 'algs/conduction/system_efficiency_assessmen.zip', 0, 'DRAFT', 'ENABLED', '0', 'admin', CAST('2023-08-22 17:37:14' AS TIMESTAMP), 'admin', NULL, NULL);
INSERT INTO pgzc_algorithm (id, algorithm_name, algorithm_type, equipment_type, algorithm_desc, algorithm_version, algorithm_code_url, base_flag, publish_status, status, del_flag, create_by, create_time, update_by, update_time, remark) VALUES (205, '判别分析法', '方案评价', '', '算法将决策问题转化为一个决策矩阵，其中每一行代表一个候选方案；确定每一组的样本数据，如优秀：优秀数据，良好：两汉数据等；分别计算每个类别的均值和协方差矩阵，并汇总协方差矩阵，计算汇总矩阵的逆和线性系数，计算分类的阈值，对所有样本进行分类。根据样本的分类结果进行排名。', 'V1', 'algs/assess/Discriminant_Analysis.zip', 0, 'DRAFT', 'ENABLED', '0', 'admin', CAST('2023-08-31 19:31:52' AS TIMESTAMP), 'admin', NULL, NULL);
INSERT INTO pgzc_algorithm (id, algorithm_name, algorithm_type, equipment_type, algorithm_desc, algorithm_version, algorithm_code_url, base_flag, publish_status, status, del_flag, create_by, create_time, update_by, update_time, remark) VALUES (207, '灰色评估法', '方案评价', '', '算法将决策问题转化为一个决策矩阵，其中每一行代表一个候选方案；计算每个数据序列与参考序列的绝对差值矩阵，计算灰色关联系数公式中的最小值和最大值，定义一个P值， 计算灰色关联系数和灰色关联度，将每一个方案的灰色关联度进行排名。', 'V1', 'algs/assess/grey_analysis.zip', 0, 'DRAFT', 'ENABLED', '0', 'admin', CAST('2023-12-27 11:31:50' AS TIMESTAMP), 'admin', CAST('2023-12-27 11:31:50' AS TIMESTAMP), NULL);
INSERT INTO pgzc_algorithm (id, algorithm_name, algorithm_type, equipment_type, algorithm_desc, algorithm_version, algorithm_code_url, base_flag, publish_status, status, del_flag, create_by, create_time, update_by, update_time, remark) VALUES (208, '连环比率法', '权重分配', '', '根据输入的各指标之间的比率，将最后一个指标记为“1份”，计算前面每一个指标的份额，最终通过比率不断向前传递确定每一个指标的份额，通过该份额计算每一个指标的权重结果。
INSERT INTO pgzc_algorithm (id, algorithm_name, algorithm_type, equipment_type, algorithm_desc, algorithm_version, algorithm_code_url, base_flag, publish_status, status, del_flag, create_by, create_time, update_by, update_time, remark) VALUES (209, '字典序法', '方案评价', '', '算法将决策问题转化为一个决策矩阵，其中每一行代表一个候选方案；确定自定义优先度字典序列即哪个指标或哪一天的指标评估结果好的优先度更高，将方案根据字典进行排序，在第一序列相同的情况下比较其第二位序列的结果，直至所有的方案排名完成。', 'V1', 'algs/assess/lexicographic_ordering.zip', 0, 'DRAFT', 'ENABLED', '0', 'admin', CAST('2023-09-05 15:15:45' AS TIMESTAMP), 'admin', CAST('2023-12-14 16:05:17' AS TIMESTAMP), NULL);
INSERT INTO pgzc_algorithm (id, algorithm_name, algorithm_type, equipment_type, algorithm_desc, algorithm_version, algorithm_code_url, base_flag, publish_status, status, del_flag, create_by, create_time, update_by, update_time, remark) VALUES (210, '模糊TOPSIS法', '方案评价', '', '算法将决策问题转化为一个决策矩阵，其中每一行代表一个候选方案；对于每个指标，确定最大值和最小值，构建理想解和负理想解；同时构建模糊理想解和负理想解，计算每个方案到模糊理想解和负理想解的欧几里得距离或其他距离度量；根据方案到模糊理想解的距离和方案到模糊负理想解的距离，计算综合得分。得分越高表示方案越优越。根据综合得分对方案进行排序，得分越高的排在前面，从而确定最优解。', 'V1', 'algs/assess/fuzzy_TOPSIS.zip', 0, 'DRAFT', 'ENABLED', '0', 'admin', CAST('2023-09-13 09:20:11' AS TIMESTAMP), 'admin', NULL, NULL);
INSERT INTO pgzc_algorithm (id, algorithm_name, algorithm_type, equipment_type, algorithm_desc, algorithm_version, algorithm_code_url, base_flag, publish_status, status, del_flag, create_by, create_time, update_by, update_time, remark) VALUES (211, '模糊综合评判', '方案评价', '', '算法将将决策问题转化为一个决策矩阵，其中每一行代表一个候选方案；定义模糊评价阈值和分值，统计每一组候选方案的各项指标的结果分类概率（如优：0.5，良0.3，差：0.2等等），根据统计结果和每组的分值去顶该组候选方案的最终得分，并根据得分结果进行排序。', 'V1', 'algs/assess/fuzzy_comprehension.zip', 0, 'DRAFT', 'ENABLED', '0', 'admin', CAST('2023-09-13 09:41:00' AS TIMESTAMP), 'admin', CAST('2023-12-14 10:36:43' AS TIMESTAMP), NULL);
INSERT INTO pgzc_algorithm (id, algorithm_name, algorithm_type, equipment_type, algorithm_desc, algorithm_version, algorithm_code_url, base_flag, publish_status, status, del_flag, create_by, create_time, update_by, update_time, remark) VALUES (213, '聚类分析法', '方案评价', '', '算法首先定义簇的个数，随机机选择一些样本作为初始簇中心根据欧几里得距离计算公式将样本划分为不同的簇，簇的中心会根据样本的相似性进行更新，通过不断迭代直至簇的中心不再发生变化，该组所有数据即为同一个簇。针对每一个簇的评估值进行统计计算，对簇进行排名。根据簇的排名对每一个簇里的元素进行排名，同一个簇排名相同。', 'V1', 'algs/assess/clustering.zip', 0, 'DRAFT', 'ENABLED', '0', 'admin', CAST('2023-09-13 11:33:39' AS TIMESTAMP), 'admin', NULL, NULL);
INSERT INTO pgzc_algorithm (id, algorithm_name, algorithm_type, equipment_type, algorithm_desc, algorithm_version, algorithm_code_url, base_flag, publish_status, status, del_flag, create_by, create_time, update_by, update_time, remark) VALUES (214, '蒙特卡洛法', '方案评价', '', '算法将将决策问题转化为一个决策矩阵，其中每一行代表一个候选方案；定义标准数据，针对该标准数据结果进行若干次（100次）蒙特卡洛模拟；对候选方案也进行若干次（100次）蒙特卡洛模拟；将这2组结果分别两两进行对比得到100*100个距离，将该组距离求平均值即为该方案与标准方案的距离，分别求所有候选方案的距离，并进行排序，距离更短的排名更靠前。', 'V1', 'algs/assess/monte_carlo_method.zip', 0, 'DRAFT', 'ENABLED', '0', 'admin', CAST('2023-09-13 15:20:20' AS TIMESTAMP), 'admin', CAST('2023-12-13 11:40:23' AS TIMESTAMP), NULL);
INSERT INTO pgzc_algorithm (id, algorithm_name, algorithm_type, equipment_type, algorithm_desc, algorithm_version, algorithm_code_url, base_flag, publish_status, status, del_flag, create_by, create_time, update_by, update_time, remark) VALUES (216, '滑动窗口', '指标量化算法', '', '算法首先设置窗口，将整个窗口视为一个整体，更新数据列表，将新的数据列表进行归一化或区间化处理。这种处理方式主要用于减少波动或单个跳点对评估结果的影响，在确定波动周期后将窗口设为波动周期大小，即可保证在数据未发生异常时评估结果稳定。', 'V1', 'algs/norm/sliding_window.zip', 0, 'DRAFT', 'ENABLED', '0', 'admin', CAST('2023-12-27 11:05:09' AS TIMESTAMP), 'admin', CAST('2023-12-27 11:05:09' AS TIMESTAMP), NULL);
INSERT INTO pgzc_algorithm (id, algorithm_name, algorithm_type, equipment_type, algorithm_desc, algorithm_version, algorithm_code_url, base_flag, publish_status, status, del_flag, create_by, create_time, update_by, update_time, remark) VALUES (218, '滚动窗口', '指标量化算法', '', '算法首先设置窗口，如7天，30天或365天等，将所有数据按照窗口分为若干份，对每一份数据都进行归一化处理，得到最终的评估结果。这种处理方式适用于已知数据具有周期性，例如光照地影年周期等数据，针对每个周期的数据进行处理，得到每个数据针对其所在周期的评估结果', 'V1', 'algs/norm/rolling_window.zip', 0, 'DRAFT', 'ENABLED', '0', 'admin', CAST('2023-09-13 16:01:36' AS TIMESTAMP), 'admin', NULL, NULL);
INSERT INTO pgzc_algorithm (id, algorithm_name, algorithm_type, equipment_type, algorithm_desc, algorithm_version, algorithm_code_url, base_flag, publish_status, status, del_flag, create_by, create_time, update_by, update_time, remark) VALUES (219, '因子分析法', '权重分配', '', '根据遥测数据的残差值计算各指标的相关系数矩阵，并进行线性检查以及协方差矩阵的行列式。对通过线性检查和协方差矩阵的行列式的数据获取特征值和方差解释率，获取载荷系数，计算每个因子旋转后的方差和解释的方差比例，计算比例系数和综合得分系数，并以此计算每一个遥测数据的权重值。
INSERT INTO pgzc_algorithm (id, algorithm_name, algorithm_type, equipment_type, algorithm_desc, algorithm_version, algorithm_code_url, base_flag, publish_status, status, del_flag, create_by, create_time, update_by, update_time, remark) VALUES (220, '极值多目标规划法', '方案评价', '', '算法初始化参数和迭代器，定义计算效率的目标函数以及约束条件，进行多目标规划的优化，找到最优的权重向量，使用最优权重向量计算每个决策单元的效率值。', 'V1', 'algs/assess/DEA.zip', 0, 'DRAFT', 'ENABLED', '0', 'admin', CAST('2023-09-14 09:24:05' AS TIMESTAMP), 'admin', NULL, NULL);
INSERT INTO pgzc_algorithm (id, algorithm_name, algorithm_type, equipment_type, algorithm_desc, algorithm_version, algorithm_code_url, base_flag, publish_status, status, del_flag, create_by, create_time, update_by, update_time, remark) VALUES (223, '分级法', '指标量化算法', '', '根据遥测数据设置级别数，分别计算每个级别对应的分数，最优级别评估值为1，最差级别评估值为0。针对级别数和标准对遥测数据进行分级处理，针对没有输入分级标准的数据认为遥测数据最大值、最小值为该段数据的分级标准，根据每个遥测所在的级别对每个遥测进行评估。', 'V1', 'algs/norm/classfication.zip', 0, 'DRAFT', 'ENABLED', '0', 'admin', CAST('2023-12-27 10:32:29' AS TIMESTAMP), 'admin', CAST('2023-12-27 10:32:29' AS TIMESTAMP), NULL);
INSERT INTO pgzc_algorithm (id, algorithm_name, algorithm_type, equipment_type, algorithm_desc, algorithm_version, algorithm_code_url, base_flag, publish_status, status, del_flag, create_by, create_time, update_by, update_time, remark) VALUES (224, '类别特性分析', '指标量化算法', '', '算法先定义分的类别数，根据所分类别数量以及数据的上下限确定每个数据所属的类别，在判断每一组类别的数据点数量，以此确定每一类别的最终评分，最后根据数据所属的类别进行打分。', 'V1', 'algs/norm/category_characteristics.zip', 0, 'DRAFT', 'ENABLED', '0', 'admin', CAST('2023-12-27 10:56:20' AS TIMESTAMP), 'admin', CAST('2023-12-27 10:56:20' AS TIMESTAMP), NULL);
INSERT INTO pgzc_algorithm (id, algorithm_name, algorithm_type, equipment_type, algorithm_desc, algorithm_version, algorithm_code_url, base_flag, publish_status, status, del_flag, create_by, create_time, update_by, update_time, remark) VALUES (227, 'sigmoid算法', '指标量化算法', '', NULL, 'V1', 'algs/norm/sigmoid.zip', 1, 'DRAFT', 'ENABLED', '0', 'admin', CAST('2024-01-05 15:25:45' AS TIMESTAMP), 'admin', CAST('2024-01-05 15:25:45' AS TIMESTAMP), NULL);
INSERT INTO pgzc_algorithm (id, algorithm_name, algorithm_type, equipment_type, algorithm_desc, algorithm_version, algorithm_code_url, base_flag, publish_status, status, del_flag, create_by, create_time, update_by, update_time, remark) VALUES (229, '无指标要求处理', '属性值计算方法', '', NULL, 'V1', 'algs/character/noInadicator.zip', 0, 'DRAFT', 'ENABLED', '0', 'admin', CAST('2023-09-18 09:53:20' AS TIMESTAMP), NULL, NULL, NULL);
INSERT INTO pgzc_algorithm (id, algorithm_name, algorithm_type, equipment_type, algorithm_desc, algorithm_version, algorithm_code_url, base_flag, publish_status, status, del_flag, create_by, create_time, update_by, update_time, remark) VALUES (236, '残差法', '指标量化算法', '', NULL, 'V1', 'algs/norm/residuals.zip', 1, 'DRAFT', 'ENABLED', '0', 'admin', CAST('2023-09-24 14:54:48' AS TIMESTAMP), NULL, NULL, NULL);
INSERT INTO pgzc_algorithm (id, algorithm_name, algorithm_type, equipment_type, algorithm_desc, algorithm_version, algorithm_code_url, base_flag, publish_status, status, del_flag, create_by, create_time, update_by, update_time, remark) VALUES (240, '统计量分析', '指标量化算法', '', '初始化结果列表，计算每个数据点相对于整个列表的偏度，通过计算四分位距，检测异常值并处理，将正常的数据偏度结果显示出来，异常值对应的评估结果为0.', 'V1', 'algs/norm/statistical_analysis.zip', 0, 'DRAFT', 'ENABLED', '0', 'admin', CAST('2023-12-27 10:35:38' AS TIMESTAMP), 'admin', CAST('2023-12-27 10:35:38' AS TIMESTAMP), NULL);
INSERT INTO pgzc_algorithm (id, algorithm_name, algorithm_type, equipment_type, algorithm_desc, algorithm_version, algorithm_code_url, base_flag, publish_status, status, del_flag, create_by, create_time, update_by, update_time, remark) VALUES (242, '置信度', '其它算法', '', '置信度', 'V1', 'algs/others/confidence.zip', 0, 'DRAFT', 'ENABLED', '0', 'admin', NULL, NULL, NULL, NULL);
INSERT INTO pgzc_algorithm (id, algorithm_name, algorithm_type, equipment_type, algorithm_desc, algorithm_version, algorithm_code_url, base_flag, publish_status, status, del_flag, create_by, create_time, update_by, update_time, remark) VALUES (245, '功效系数法', '权重传导', '', '算法定义三种得分转换函数，用于对原始得分进行某种变换，以便更好地反映产品的特性或对得分进行标准化。通过得分转换函数得到每个产品的得分，使用得分对产品进行排序，得到排名。排名按得分从高到低排列，即得分最高的产品排在第一位。', 'V1', 'algs/conduction/Efficacy_Coefficient.zip', 0, 'DRAFT', 'ENABLED', '0', 'admin', CAST('2023-10-27 19:54:12' AS TIMESTAMP), 'admin', NULL, NULL);
INSERT INTO pgzc_algorithm (id, algorithm_name, algorithm_type, equipment_type, algorithm_desc, algorithm_version, algorithm_code_url, base_flag, publish_status, status, del_flag, create_by, create_time, update_by, update_time, remark) VALUES (246, '层次分析法', '权重分配', '', '专家将指标进行两两比较，记录比值，得到比较矩阵。对矩阵进行特征根分解，并找到最大特征值的索引，以确定主特征向量，提取与最大特征值相对应的主特征向量，主特征向量标准化为单位向量，并计算得到的权重。', 'V1', 'algs/weight/ahp.zip', 0, 'DRAFT', 'ENABLED', '0', 'admin', CAST('2023-10-30 09:19:58' AS TIMESTAMP), 'admin', CAST('2023-12-15 11:30:02' AS TIMESTAMP), NULL);
INSERT INTO pgzc_algorithm (id, algorithm_name, algorithm_type, equipment_type, algorithm_desc, algorithm_version, algorithm_code_url, base_flag, publish_status, status, del_flag, create_by, create_time, update_by, update_time, remark) VALUES (247, '基于模糊层次分析与相似度法', '权重分配', '', '专家输入每一个指标的参考重要程度和参考权重，并将参考重要程度进行两两比较，记录比值，得到比较矩阵。对矩阵进行特征根分解，并找到最大特征值的索引，以确定主特征向量，提取与最大特征值相对应的主特征向量，主特征向量标准化为单位向量，并计算得到的权重。将计算得到的权重和参考权重进行对比，并将相似度融入到权重计算中，得到一个综合的权重。', 'V1', 'algs/weight/ahp_similarity.zip', 0, 'DRAFT', 'ENABLED', '0', 'admin', CAST('2023-10-30 09:21:21' AS TIMESTAMP), 'admin', NULL, NULL);
INSERT INTO pgzc_algorithm (id, algorithm_name, algorithm_type, equipment_type, algorithm_desc, algorithm_version, algorithm_code_url, base_flag, publish_status, status, del_flag, create_by, create_time, update_by, update_time, remark) VALUES (248, '相对比较法', '权重分配', '', '专家输入每一个指标的参考重要程度，并进行两两比较，如果A比B重要则A记为1，B记为0，A和B同样重要则A和B均记为0.5，计算所有指标的最终得分。根据得分占总分的比例计算每一个指标的权重。', 'V1', 'algs/weight/pairwise_comparison.zip', 0, 'DRAFT', 'ENABLED', '0', 'admin', CAST('2023-10-30 09:26:11' AS TIMESTAMP), 'admin', NULL, NULL);
INSERT INTO pgzc_algorithm (id, algorithm_name, algorithm_type, equipment_type, algorithm_desc, algorithm_version, algorithm_code_url, base_flag, publish_status, status, del_flag, create_by, create_time, update_by, update_time, remark) VALUES (249, 'ADC法', '权重传导', '', '将原有数据分为E为效能，A为有效性，D为可信赖性，C为能力，其中能力即为对各项指标的评估值。有效性和可依赖性为可配置的列表，可由专家经验进行参数的配置。', 'V1', 'algs/conduction/ADC.zip', 0, 'DRAFT', 'ENABLED', '0', 'admin', CAST('2023-10-30 10:32:39' AS TIMESTAMP), 'admin', NULL, NULL);
INSERT INTO pgzc_algorithm (id, algorithm_name, algorithm_type, equipment_type, algorithm_desc, algorithm_version, algorithm_code_url, base_flag, publish_status, status, del_flag, create_by, create_time, update_by, update_time, remark) VALUES (250, '多维度模糊推理与层次分析', '权重分配', '', '项目下分为几个大环境，每个大环境有若干个条件因素。根据大环境之间的重要关系，和每个大环境下条件因素的重要关系来最终评估。', 'V1', 'algs/weight/multi_level_analysis.zip', 0, 'DRAFT', 'ENABLED', '0', 'admin', CAST('2023-10-31 11:00:38' AS TIMESTAMP), 'admin', NULL, NULL);
INSERT INTO pgzc_algorithm (id, algorithm_name, algorithm_type, equipment_type, algorithm_desc, algorithm_version, algorithm_code_url, base_flag, publish_status, status, del_flag, create_by, create_time, update_by, update_time, remark) VALUES (251, '基于对数最小二乘的模糊层次分析法', '权重分配', '', '定义一至多个评判维度的权重，分别针对每一组评判维度给出相应的重要程度；将数据转化为比较矩阵；获取矩阵的行数；对矩阵元素进行对数转换；计算每行元素和的平均值，对每行的元素和进行指数运算并返回标准化的权重。该方法回扩大强调相对较大的元素和及其重要性。', 'V1', 'algs/weight/fuzzy_AHP_with_log_least_squares.zip', 0, 'DRAFT', 'ENABLED', '0', 'admin', CAST('2023-10-31 11:11:48' AS TIMESTAMP), 'admin', NULL, NULL);
INSERT INTO pgzc_algorithm (id, algorithm_name, algorithm_type, equipment_type, algorithm_desc, algorithm_version, algorithm_code_url, base_flag, publish_status, status, del_flag, create_by, create_time, update_by, update_time, remark) VALUES (252, '升伽马型分布', '指标量化算法', '', '定义内部函数-升伽马函数，根据升伽马的升伽马系数确定升伽马曲线。确定属性值的第一个值处在升伽马曲线的位置，将该位置作为起始点，计算每一个遥测数据的属性值与升伽马曲线的距离。将该距离作为成本型指标进行对数归一化处理，将该处理结果作为升伽马分布的评估值。', 'V1', 'algs/norm/upgama_calculation.zip', 0, 'DRAFT', 'ENABLED', '0', 'admin', CAST('2023-12-27 09:34:26' AS TIMESTAMP), 'admin', CAST('2023-12-27 09:34:26' AS TIMESTAMP), NULL);
INSERT INTO pgzc_algorithm (id, algorithm_name, algorithm_type, equipment_type, algorithm_desc, algorithm_version, algorithm_code_url, base_flag, publish_status, status, del_flag, create_by, create_time, update_by, update_time, remark) VALUES (253, '相似度法', '指标量化算法', '', '取测试段数据每一天的所有指标值，取测试段数据第一天的所有指标值，通过余弦相似度的方式，获得测试段每一天相对于基准段的相似度。', 'V1', 'algs/norm/similarity_method.zip', 1, 'DRAFT', 'ENABLED', '0', 'admin', CAST('2023-12-27 11:12:42' AS TIMESTAMP), 'admin', CAST('2023-12-27 11:12:42' AS TIMESTAMP), NULL);
INSERT INTO pgzc_algorithm (id, algorithm_name, algorithm_type, equipment_type, algorithm_desc, algorithm_version, algorithm_code_url, base_flag, publish_status, status, del_flag, create_by, create_time, update_by, update_time, remark) VALUES (259, '理论证据法', '权重分配', '', '由专家输入两组参考权重值，作为综合评估的证据一和证据二。定义冲突函数用于生成证据之间的冲突组合。', 'V1', 'algs/weight/evidence_fusionMethod.zip', 0, 'DRAFT', 'ENABLED', '0', 'admin', CAST('2023-11-01 10:44:06' AS TIMESTAMP), 'admin', NULL, NULL);
INSERT INTO pgzc_algorithm (id, algorithm_name, algorithm_type, equipment_type, algorithm_desc, algorithm_version, algorithm_code_url, base_flag, publish_status, status, del_flag, create_by, create_time, update_by, update_time, remark) VALUES (264, '效度', '其它算法', '', '效度', 'V1', 'algs/others/effi.zip', 0, 'DRAFT', 'ENABLED', '0', 'admin', NULL, NULL, NULL, NULL);
INSERT INTO pgzc_algorithm (id, algorithm_name, algorithm_type, equipment_type, algorithm_desc, algorithm_version, algorithm_code_url, base_flag, publish_status, status, del_flag, create_by, create_time, update_by, update_time, remark) VALUES (265, '周期过程指标算法', '指标量化算法', '', NULL, 'V1', 'algs/norm/cycle_process_indicator.zip', 1, 'DRAFT', 'ENABLED', '0', 'admin', CAST('2023-11-08 20:16:36' AS TIMESTAMP), NULL, NULL, NULL);
