INSERT INTO pgzc_algorithm (id, algorithm_name, algorithm_type, equipment_type, algorithm_desc, algorithm_version, algorithm_code_url, base_flag, publish_status, status, del_flag, create_by, create_time, update_by, update_time, remark) VALUES (304, '高斯均值（单独）', '指标量化算法', '', NULL, 'V1', 'algs/norm/gaussianTest.zip', 1, 'DRAFT', 'ENABLED', '0', 'admin', CAST('2024-01-05 10:40:28' AS TIMESTAMP), 'admin', CAST('2024-01-05 10:40:28' AS TIMESTAMP), NULL);
INSERT INTO pgzc_algorithm (id, algorithm_name, algorithm_type, equipment_type, algorithm_desc, algorithm_version, algorithm_code_url, base_flag, publish_status, status, del_flag, create_by, create_time, update_by, update_time, remark) VALUES (305, '阈值法', '指标量化算法', '', '基于早期基准段遥测值计算基准极大值和极小值，若该遥测指标具有年周期包络特性，使用年周期的门限值作为基准极大值和极小值。通过计算极大值和极小值间的距离，将该距离向两侧各扩大（range-1）倍，作为新的门限值。对于有年周期包络的情况，将该门限值内的评估值置为1，超出门限范围的根据门限大小等比进行评估。', 'V1', 'algs/norm/20231228_intervalize_new.zip', 1, 'DRAFT', 'ENABLED', '0', 'admin', CAST('2024-01-11 15:30:06' AS TIMESTAMP), 'admin', CAST('2024-01-11 15:30:06' AS TIMESTAMP), NULL);
INSERT INTO pgzc_algorithm (id, algorithm_name, algorithm_type, equipment_type, algorithm_desc, algorithm_version, algorithm_code_url, base_flag, publish_status, status, del_flag, create_by, create_time, update_by, update_time, remark) VALUES (306, '计算均值(属性值)', '属性值计算方法', '', NULL, 'V1', 'algs/character/calMean.zip', 0, 'DRAFT', 'ENABLED', '0', 'admin', CAST('2023-12-28 15:41:25' AS TIMESTAMP), 'admin', CAST('2023-12-28 15:41:25' AS TIMESTAMP), NULL);
INSERT INTO pgzc_algorithm (id, algorithm_name, algorithm_type, equipment_type, algorithm_desc, algorithm_version, algorithm_code_url, base_flag, publish_status, status, del_flag, create_by, create_time, update_by, update_time, remark) VALUES (307, '极大化法', '指标量化算法', '', '基于早期基准段遥测值计算正向分布时的基准极大值和极小值，若该遥测指标具有年周期包络特性，使用年周期的门限值作为基准极大值和极小值。通过计算极大值和极小值间的距离，作为门限值。以门限值的最大值作为基准，根据新的门限进行区间化。', 'V1', 'algs/norm/20231228forward_normalize_new.zip', 1, 'DRAFT', 'ENABLED', '0', 'admin', CAST('2024-01-11 15:29:08' AS TIMESTAMP), 'admin', CAST('2024-01-11 15:29:08' AS TIMESTAMP), NULL);
INSERT INTO pgzc_algorithm (id, algorithm_name, algorithm_type, equipment_type, algorithm_desc, algorithm_version, algorithm_code_url, base_flag, publish_status, status, del_flag, create_by, create_time, update_by, update_time, remark) VALUES (308, '极小化法', '指标量化算法', '', '基于早期基准段遥测值计算正向分布时的基准极大值和极小值，若该遥测指标具有年周期包络特性，使用年周期的门限值作为基准极大值和极小值。通过计算极大值和极小值间的距离，作为门限值。以门限值的最小值作为基准，根据新的门限进行逆向区间化。该算法适用于成本型数据，即遥测值越小其评估值越大。', 'V1', 'algs/norm/20231228inverse_normalize_new.zip', 1, 'DRAFT', 'ENABLED', '0', 'admin', CAST('2024-01-11 15:29:26' AS TIMESTAMP), 'admin', CAST('2024-01-11 15:29:26' AS TIMESTAMP), NULL);
