INSERT INTO pgzc_algorithm (id, algorithm_name, algorithm_type, equipment_type, algorithm_desc, algorithm_version, algorithm_code_url, base_flag, publish_status, status, del_flag, create_by, create_time, update_by, update_time, remark) VALUES (333, '半正态分布', '指标量化算法', '', '算法根据所有基准数据计算均值和标准差，即可获得半正态分布的概率密度函数，将每个数据点的在半正态分布的概率密度作为其评估结果。', 'V1', 'algs/norm/half_normal_distribution.zip', 1, 'DRAFT', 'ENABLED', '0', 'admin', CAST('2024-01-11 15:27:01' AS TIMESTAMP), 'admin', CAST('2024-01-11 15:27:01' AS TIMESTAMP), NULL);
INSERT INTO pgzc_algorithm (id, algorithm_name, algorithm_type, equipment_type, algorithm_desc, algorithm_version, algorithm_code_url, base_flag, publish_status, status, del_flag, create_by, create_time, update_by, update_time, remark) VALUES (334, '横向对比', '指标量化算法', '', '使用其他型号的某星的任意时段数据作为基准数据，通过对基准数据进行计算均值和标准差作为高斯分布的参数值，将测试型号的测试数据使用标准的高斯函数进行量化评估，其概率密度即为评评估结果。', 'V1', 'algs/norm/horizontal_comparison.zip', 1, 'DRAFT', 'ENABLED', '0', 'admin', CAST('2024-01-11 15:27:10' AS TIMESTAMP), 'admin', CAST('2024-01-11 15:27:10' AS TIMESTAMP), NULL);
INSERT INTO pgzc_algorithm (id, algorithm_name, algorithm_type, equipment_type, algorithm_desc, algorithm_version, algorithm_code_url, base_flag, publish_status, status, del_flag, create_by, create_time, update_by, update_time, remark) VALUES (335, '纵向对比', '指标量化算法', '', '使用该型号的历史数据作为基准数据，通过对基准数据进行计算均值和标准差作为高斯分布的参数值，将该型号的测试数据使用标准的高斯函数进行量化评估，其概率密度即为评评估结果。', 'V1', 'algs/norm/longitudinal_comparison.zip', 1, 'DRAFT', 'ENABLED', '0', 'admin', CAST('2024-01-11 15:27:06' AS TIMESTAMP), 'admin', CAST('2024-01-11 15:27:06' AS TIMESTAMP), NULL);
INSERT INTO pgzc_algorithm (id, algorithm_name, algorithm_type, equipment_type, algorithm_desc, algorithm_version, algorithm_code_url, base_flag, publish_status, status, del_flag, create_by, create_time, update_by, update_time, remark) VALUES (336, '计算姿态机动时段平均速度（属性值计算-非连续侧摆类卫星）', '属性值计算方法', '', '计算姿态机动的时间起止点方法①：对于非连续侧摆类卫星，比如JB140A/B，有较长的姿态稳定时间，开始时刻为姿态角发生变化的时刻，其结束时刻为连续3拍姿态角差值小于一定姿态稳定度阈值（姿态控制精度，来源于卫星设计指标）的第1拍时刻；两个时刻对应的姿态角做差，即为姿态角增量。', 'V1', 'algs/character/average_velocity.zip', 0, 'DRAFT', 'ENABLED', '0', 'admin', CAST('2024-01-06 10:08:09' AS TIMESTAMP), 'admin', CAST('2024-01-06 10:08:09' AS TIMESTAMP), NULL);
INSERT INTO pgzc_algorithm (id, algorithm_name, algorithm_type, equipment_type, algorithm_desc, algorithm_version, algorithm_code_url, base_flag, publish_status, status, del_flag, create_by, create_time, update_by, update_time, remark) VALUES (337, '计算姿态机动时段平均速度（属性值计算-敏捷类卫星）', '属性值计算方法', '', '计算姿态机动的时间起止点方法②：对于连续侧摆类敏捷卫星，比如JB1205、JB24号B系列卫星，没有姿态稳定时间，通过局部极值检测算法，检测出轨道周期内连续变化曲线的极小值、极大值或者极大值、极小值，分别作为姿态机动时间的起点、终点；两个时刻对应的姿态角做差，即为姿态角增量。', 'V1', 'algs/character/average_velocity_agility.zip', 0, 'DRAFT', 'ENABLED', '0', 'admin', CAST('2024-01-06 10:20:01' AS TIMESTAMP), NULL, NULL, NULL);
INSERT INTO pgzc_algorithm (id, algorithm_name, algorithm_type, equipment_type, algorithm_desc, algorithm_version, algorithm_code_url, base_flag, publish_status, status, del_flag, create_by, create_time, update_by, update_time, remark) VALUES (338, '温度控制能力均值（属性值计算）', '属性值计算方法', '', '计算精密温度部件（星敏、地敏、时钟、光纤陀螺、蓄电池、贮箱等）、转动部件（[动量轮]/[反作用轮]/[控制力矩陀螺]、机械陀螺等）、平台舱、载荷舱的温度均值', 'V1', 'algs/character/caTemplMean.zip', 0, 'DRAFT', 'ENABLED', '0', 'admin', CAST('2024-01-06 10:30:53' AS TIMESTAMP), NULL, NULL, NULL);
INSERT INTO pgzc_algorithm (id, algorithm_name, algorithm_type, equipment_type, algorithm_desc, algorithm_version, algorithm_code_url, base_flag, publish_status, status, del_flag, create_by, create_time, update_by, update_time, remark) VALUES (339, '温度控制能力标准差（属性值计算）', '属性值计算方法', '', '计算精密温度部件（星敏、地敏、时钟、光纤陀螺、蓄电池、贮箱等）、转动部件（[动量轮]/[反作用轮]/[控制力矩陀螺]、机械陀螺等）、平台舱、载荷舱的温度标准差的均值', 'V1', 'algs/character/calTempStandardDeviation.zip', 0, 'DRAFT', 'ENABLED', '0', 'admin', CAST('2024-01-06 10:56:12' AS TIMESTAMP), 'admin', CAST('2024-01-06 10:56:12' AS TIMESTAMP), NULL);
