INSERT INTO pgzc_algorithm (id, algorithm_name, algorithm_type, equipment_type, algorithm_desc, algorithm_version, algorithm_code_url, base_flag, publish_status, status, del_flag, create_by, create_time, update_by, update_time, remark) VALUES (341, '充电终压（属性值计算）', '属性值计算方法', '', '蓄电池充电开始后，若连续5拍蓄电池电压与设计值（设计文件）的差值小于一定阈值（设计值的百分之一）范围内，作为蓄电池充电终压', 'V1', 'algs/character/chargingFinalVoltage.zip', 0, 'DRAFT', 'ENABLED', '0', 'admin', CAST('2024-01-24 20:50:44' AS TIMESTAMP), 'admin', CAST('2024-01-24 20:50:44' AS TIMESTAMP), NULL);
